import React, { useState } from 'react';
import api from '../services/api';

export default function RatingPanel() {
  const user    = JSON.parse(localStorage.getItem('zipride_user') || '{}');
  const role    = user.role || 'PASSENGER';
  const isAdmin = role === 'ADMIN';

  const [form,          setForm]          = useState({ driverId:'', rideRequestId:'', passengerId:'', rating:'5', comment:'' });
  const [result,        setResult]        = useState(null);
  const [warnedDrivers, setWarnedDrivers] = useState(null);
  const [loading,       setLoading]       = useState(false);

  const submit = async e => {
    e.preventDefault(); setLoading(true); setResult(null);
    try {
      const { data } = await api.post('/api/ratings/submit', {
        driverId: parseInt(form.driverId), rideRequestId: parseInt(form.rideRequestId),
        passengerId: parseInt(form.passengerId), rating: parseFloat(form.rating), comment: form.comment
      });
      setResult(data);
    } catch (err) { setResult({ message: err.response?.data?.message || 'Error' }); }
    finally { setLoading(false); }
  };

  const fetchWarned = async () => {
    try { const { data } = await api.get('/api/ratings/warned-drivers'); setWarnedDrivers(data); } catch {}
  };

  const stars = n => Array.from({ length:5 }, (_, i) => (
    <span key={i} style={{ cursor:'pointer', fontSize:22, color: i < n ? '#C9A84C' : 'var(--border)' }}
      onClick={() => setForm({ ...form, rating: String(i + 1) })}>★</span>
  ));

  return (
    <>
      {/* ── PASSENGER + ADMIN: Submit Rating ────────────────────── */}
      <div className="panel">
        <div className="panel-header">
          <h3>Submit Driver Rating</h3>
          <span className="badge">POST /api/ratings/submit</span>
        </div>
        <div className="panel-body">
          <form onSubmit={submit}>
            <div className="form-row">
              <div className="form-group"><label>Driver ID</label><input placeholder="1" value={form.driverId} onChange={e => setForm({...form, driverId: e.target.value})} /></div>
              <div className="form-group"><label>Ride Request ID</label><input placeholder="1" value={form.rideRequestId} onChange={e => setForm({...form, rideRequestId: e.target.value})} /></div>
              <div className="form-group"><label>Passenger ID</label><input placeholder="1" value={form.passengerId} onChange={e => setForm({...form, passengerId: e.target.value})} /></div>
            </div>
            <div className="form-group">
              <label>Rating</label>
              <div style={{ display:'flex', gap:4, marginBottom:8 }}>{stars(parseInt(form.rating))}</div>
              <input type="range" min="1" max="5" step="0.5" value={form.rating}
                onChange={e => setForm({...form, rating: e.target.value})}
                style={{ width:'100%', accentColor:'var(--gold)' }} />
              <div style={{ color:'var(--gold)', fontSize:14, marginTop:4 }}>{form.rating} / 5.0</div>
            </div>
            <div className="form-group"><label>Comment (optional)</label>
              <input placeholder="Great driver, very punctual!" value={form.comment} onChange={e => setForm({...form, comment: e.target.value})} />
            </div>
            <button className="btn-action" type="submit" disabled={loading}>
              {loading && <span className="spinner" />} Submit Rating
            </button>
          </form>

          {result && (
            <div className="result-card">
              <h4>Rating Result</h4>
              <div className="result-row"><span className="rk">Message</span><span className="rv" style={{ fontSize:13 }}>{result.message}</span></div>
              {result.newRollingAverageRating !== undefined && <>
                <div className="result-row"><span className="rk">New Rolling Avg</span><span className="rv highlight">★ {result.newRollingAverageRating?.toFixed(2)}</span></div>
                <div className="result-row"><span className="rk">Ratings Considered</span><span className="rv">{result.totalRatingsConsidered}</span></div>
                <div className="result-row"><span className="rk">Warning Flagged</span>
                  <span className={`rv ${result.warningFlagged ? 'error' : 'success'}`}>{result.warningFlagged ? '⚠ YES' : '✓ No'}</span>
                </div>
                {result.incentiveBonusAwarded && Object.entries(result.incentiveBonusAwarded).map(([period, amt]) => (
                  <div className="result-row" key={period}>
                    <span className="rk">{period} Bonus</span>
                    <span className={`rv ${amt > 0 ? 'success' : ''}`}>{amt > 0 ? `₹${amt} awarded` : 'Not eligible'}</span>
                  </div>
                ))}
              </>}
            </div>
          )}
        </div>
      </div>

      {/* ── ADMIN ONLY: Warned Drivers ───────────────────────────── */}
      {isAdmin && (
        <div className="panel">
          <div className="panel-header">
            <h3>Warned Drivers</h3>
            <span className="badge">ADMIN only · GET /api/ratings/warned-drivers</span>
          </div>
          <div className="panel-body">
            <button className="btn-action" onClick={fetchWarned}>Load Warned Drivers</button>
            {warnedDrivers && (
              <div className="result-card" style={{ marginTop:20 }}>
                <h4>Flagged Drivers ({warnedDrivers.length})</h4>
                {warnedDrivers.length === 0
                  ? <p style={{ color:'var(--text-muted)', fontSize:13 }}>No drivers currently flagged.</p>
                  : warnedDrivers.map(d => (
                    <div className="result-row" key={d.id}>
                      <span className="rk">#{d.id} {d.driverName}</span>
                      <span className="rv error">★ {d.rollingAverageRating?.toFixed(2)} — {d.warningReason?.slice(0,60)}…</span>
                    </div>
                  ))
                }
              </div>
            )}
          </div>
        </div>
      )}
    </>
  );
}
